//设置工作路径为JS文件所在路径
setCurDir(getSrcDir());

//清楚PDyna中内存数据
dyna.Clear();

//设置结果输出时步为500步
dyna.Set("Output_Interval 500");

//创建规则排布的颗粒
pdyna.RegularCreateByCoord(2, 1, 0.5, -10, 10, -10, 10, 0,0);

//设置颗粒模型为线弹性模型
pdyna.SetModel("linear");

//设置材料参数，依次为密度、弹性模量、泊松比、抗拉强度、粘聚力、内摩擦角、局部阻尼、粘性阻尼系数（临界阻尼比）
pdyna.SetMat(2500, 3e10, 0.25, 0, 0, 45, 0.8, 0.0);

//固定模型底部速度
pdyna.FixV("xyz", 0.0,"y", -11, -9);

//加载动态链接库
dyna.LoadUDF("CustomModel");

//运行动态链接库中的函数，自定义命令流
dyna.RunUDFCmd("CalDist 0 0 0 10 10 0");

//打开允许用户在核心迭代中加入自定义函数功能
dyna.Set("If_Allow_UDF_Kernel 1");

//求解
dyna.Solve();

//释放动态链接库
dyna.FreeUDF();

//设置当前路径为JavaScript脚本所在的路径
setCurDir(getSrcDir());

//设置结果的输出间隔为500步
dyna.Set("Output_Interval 1000");

//关闭虚拟质量开关
dyna.Set("If_Virtural_Mass 0");

//设置重力加速度
dyna.Set("Gravity 0.0 -9.8 0.0");

//设置接触容差
dyna.Set("Contact_Detect_Tol 0.0");

dyna.Set("GiD_Out 1");

//设置底部刚性面
var fCoord = [-1.0,0.0,0.0,2.0,0.0,0.0];
rdface.Create (1, 1, 2, fCoord);

var fCoord2 = [-1.0,0.0,0.0,-1.0,2.0,0.0];
var fCoord3 = [2.0,0.0,0.0,2.0,2.0,0.0];
rdface.Create (1, 1, 2, fCoord2);
rdface.Create (1, 1, 2, fCoord3);

//导入pdyna格式的颗粒并创建椭圆
pdyna.CrtEllipsePartFromFile("1m-1m-ball.dat", "uniform", 0.8,1, "uniform", 0.2,1, "uniform", 0.0, 360.0, 12);

//设置颗粒的材料参数，依次为密度、弹性模量、泊松比、抗拉强度、粘聚力、内摩擦角、局部阻尼、粘性阻尼系数（临界阻尼比）
pdyna.SetPartMat(2500, 5e7, 0.25, 0.0, 0.0, 10, 0.01, 0.1, 0.1);

//设置颗粒接触模型为考虑应变软化的Mohr-Coulomb模型
pdyna.SetModel("brittleMC");

//设置动态计算时步为1e-4秒
dyna.Set("Time_Step 1e-5");

//计算3万步
dyna.Solve(100000);

//设置当前路径为JavaScript脚本所在的路径
setCurDir(getSrcDir());

//清除GDEM-Pdyna计算核心中的内存数据
dyna.Clear();

//清除GDEM-Env中的结果数据
doc.clearResult();

//设置输出的间隔为500步
dyna.Set("Output_Interval 500");

//关闭虚质量计算开关
dyna.Set("If_Virtural_Mass 0");

//设置三个方向的全局重力加速度为0
dyna.Set("Gravity 0.0 -9.8 0.0");

//打开单元大变形计算开关
dyna.Set("Large_Displace 1");

//打开单元接触更新开关
dyna.Set("If_Renew_Contact 1");

//设置接触容差为0
dyna.Set("Contact_Detect_Tol 0.0");

//设置计算时步为4e-5
dyna.Set("Time_Step 4e-5");

//创建长宽为1m，厚5cm的板
blkdyn.ImportGrid("gid","element.msh");

//设置单元模型为线弹性模型
blkdyn.SetModel("SoftenMC");

//设置单元材料，依次为密度、弹性模量、泊松比、粘聚力、抗拉强度、内摩擦角、剪胀角
blkdyn.SetMat(2500, 1e8,0.25, 8e5, 8e5, 35, 15);

//设置单元的局部阻尼
blkdyn.SetLocalDamp(0.05);

//导入颗粒数据
pdyna.Import("pdyna","particle.dat");

//设置颗粒模型为脆性断裂模型
pdyna.SetModel("brittleMC");

//设置颗粒材料参数，依次为密度、弹性模量、泊松比、抗拉强度、粘聚力、内摩擦角、局部阻尼、粘性阻尼系数（临界阻尼比）
pdyna.SetMat(2500, 1e8, 0.25, 8e5, 8e5, 35, 0.0, 0.05);

//创建顶部刚性面
var fCoord = new Array();
fCoord[0]=new Array(-2,0.0,0.0);
fCoord[1]=new Array(2,0.0,0.0);
rdface.Create (1, 1, 2, fCoord);

//设置FEM-DEM耦合开关
dyna.Set("If_Cal_FEM_DEM_Evolvement 1");

//求解2万步
dyna.Solve(20000);

//打印信息
print("Solution is ok!");

//设置当前路径为JavaScript脚本所在的路径
setCurDir(getSrcDir());

//清除GDEM-Pdyna计算核心中的内存数据
dyna.Clear();

//清除GDEM-Env中的结果数据
doc.clearResult();

//设置输出的间隔为500步
dyna.Set("Output_Interval 500");

//关闭虚质量计算开关
dyna.Set("If_Virtural_Mass 0");

//设置三个方向的全局重力加速度为0
dyna.Set("Gravity 0.0 -9.8 0.0");

//打开单元大变形计算开关
dyna.Set("Large_Displace 1");

//打开单元接触更新开关
dyna.Set("If_Renew_Contact 1");

//设置接触容差为0
dyna.Set("Contact_Detect_Tol 0.0");

//设置计算时步为4e-5
dyna.Set("Time_Step 4e-5");

//创建长宽为1m，厚5cm的板
blkdyn.ImportGrid("gid","element.msh");

//设置单元模型为线弹性模型
blkdyn.SetModel("SoftenMC");

//设置单元材料，依次为密度、弹性模量、泊松比、粘聚力、抗拉强度、内摩擦角、剪胀角
blkdyn.SetMat(2500, 1e8,0.25, 8e5, 8e5, 35, 15);

//设置单元的局部阻尼
blkdyn.SetLocalDamp(0.05);

//导入颗粒数据
pdyna.Import("pdyna","particle.dat");

//设置颗粒模型为脆性断裂模型
pdyna.SetModel("brittleMC");

//设置颗粒材料参数，依次为密度、弹性模量、泊松比、抗拉强度、粘聚力、内摩擦角、局部阻尼、粘性阻尼系数（临界阻尼比）
pdyna.SetMat(2500, 1e8, 0.25, 8e5, 8e5, 35, 0.0, 0.05);

//创建顶部刚性面
var fCoord = new Array();
fCoord[0]=new Array(-2,0.0,0.0);
fCoord[1]=new Array(2,0.0,0.0);
rdface.Create (1, 1, 2, fCoord);

//设置FEM-DEM耦合开关
dyna.Set("If_Cal_FEM_DEM_Evolvement 1");

//求解2万步
dyna.Solve(20000);

//打印信息
print("Solution is ok!");

//设置当前工作路径为JavaScript脚本文件所在路径
setCurDir(getSrcDir());

dyna.Clear();
doc.clearResult();

//打开力学计算开关
dyna.Set("Mechanic_Cal 1");

//设置不平衡率为1e-5
dyna.Set("UnBalance_Ratio 1e-5");

//设置3个方向的重力加速度均为0.0
dyna.Set("Gravity 0 0.0 0");

//关闭大变形计算开关
dyna.Set("Large_Displace 1");

dyna.Set("If_Renew_Contact 1")

//设置结果输出时步为500步
dyna.Set("Output_Interval 500");

//监测信息的输出时步为100步
dyna.Set("Moniter_Iter 100");

//打开虚拟质量计算开关
dyna.Set("If_Virtural_Mass 0");

//设置虚拟时步为0.5
dyna.Set("Virtural_Step 0.5");

dyna.Set("Contact_Detect_Tol 0.0");

dyna.Set("BB_Contact_GroupLU 2 2");

dyna.Set("Bar_Kill_Option 1 0.5 0.5");

dyna.Set("Bar_Couple_Type 3");

blkdyn.ImportGrid("ansys","ansys-mesh.dat");

blkdyn.CrtIFace(1);
blkdyn.CrtBoundIFaceByGroup(2);

blkdyn.UpdateIFaceMesh();

//设置实体单元为线弹性模型
blkdyn.SetModel("linear");

//设置楼板参数
blkdyn.SetMat(2500, 3e10, 0.25, 3e6, 1e6, 30.0, 10.0, 1);

//设置冲击球参数
blkdyn.SetMat(12800, 5e11, 0.27, 1e9, 1e9, 0.0, 0.0, 2);

//左右两侧全约束
blkdyn.FixV("xy", 0.0, "x", -0.001, 0.001);
blkdyn.FixV("xy", 0.0, "x", 2.0-0.001, 2.0 + 0.001);

//设定所有接触面的本构为脆性断裂的Mohr-Coulomb本构
blkdyn.SetIModel("SSMC");

//设定接触面上的材料，依次为单位面积法向刚度、单位面积切向刚度、内摩擦角、粘聚力、抗拉强度
blkdyn.SetIStiffByElem(10.0);

blkdyn.SetIStrengthByElem();

//设置局部阻尼为0.2
blkdyn.SetLocalDamp(0.01);

// blkdyn.InitConditionByCoord(strCondition,fArrayVar[3], fArrayGrad[9], x0, x1, y0, y1

//设置实体单元为线弹性模型
blkdyn.SetModel("linear");

//设置楼板参数
blkdyn.SetMat(2500, 3e10, 0.25, 3e6, 1e6, 30.0, 10.0, 1);

//设置冲击球参数
blkdyn.SetMat(12800, 5e11, 0.27, 1e9, 1e9, 0.0, 0.0, 2);

//左右两侧全约束
blkdyn.FixV("xy", 0.0, "x", -0.001, 0.001);
blkdyn.FixV("xy", 0.0, "x", 2.0-0.001, 2.0 + 0.001);

//设定所有接触面的本构为脆性断裂的Mohr-Coulomb本构
blkdyn.SetIModel("SSMC");

//设定接触面上的材料，依次为单位面积法向刚度、单位面积切向刚度、内摩擦角、粘聚力、抗拉强度
blkdyn.SetIStiffByElem(10.0);

blkdyn.SetIStrengthByElem();

//设置局部阻尼为0.2
blkdyn.SetLocalDamp(0.01);

//设置当前工作路径为JavaScript脚本文件所在路径
setCurDir(getSrcDir());

//计算结果输出间隔为2000步
scdem.outputInterval = 2000;

scdem.monitorIter = 100;

//打开虚质量计算开关
scdem.isVirtualMass = 1;

//虚时步
scdem.virtualStep = 0.5;

scdem.set("isLargeDisplace", 0);

//创建半径为2cm的圆盘
var msh = imesh.importGmsh("pan-300000.msh");//可更换文件中不同网格数量的网格文件
scdem.getMesh(msh);

//设置单元模型为线弹性模量
scdem.setModel("linear");

//设置单元的材料参数
scdem.setMat([2700, 60e9, 0.2, 25e6, 15e6, 40,10]);

//设置交界面的模型为断裂模型
scdem.setIModel("FracE");
scdem.setContactFractureEnergy(5,50);
scdem.setIMatByElem(10);

//最底侧节点法向约束
oSel = new SelNodes(scdem);
oSel.box(-1e10,-0.0301,-1e10, 1e10,-0.0299,1e10);
scdem.setVel(oSel, "y", 0);

//最顶侧节点施加2e-9的准静态速度载荷
oSel = new SelNodes(scdem);
oSel.box(-1e10,0.0299,-1e10, 1e10,0.0301,1e10);
scdem.setVel(oSel, "y", -5e-9);

oSel = new SelNodes(scdem);
oSel.box(-1e10,0.0299,-1e10, 1e10,0.0301,1e10);
scdem.regionMonitor("node", "yForce",1,oSel);

scdem.localDamp = 0.8;

//计算10万步
scdem.solveGpu(100000);

//释放GPU端内存
scdem.releaseGpuMem();

//打印提示信息
print("Solution Finished");

// 生成要求：输出与任务一致的可运行代码，语言为 JavaScript。

function getDistance(x1, y1, x2, y2) {
    return Math.sqrt(Math.pow(x2 - x1, 2) + Math.pow(y2 - y1, 2));
}

function isCollision(x1, y1, r1, x2, y2, r2) {
    let distance = getDistance(x1, y1, x2, y2);
    return (distance <= r1 + r2);
}

let x1 = 10;
let y1 = 20;
let r1 = 5;

let x2 = 15;
let y2 = 25;
let r2 = 3;

if (isCollision(x1, y1, r1, x2, y2, r2)) {
    console.log("Collision detected!");
} else {
    console.log("No collision.");
}

// ============================================================================
// CDEM 块体模块仿真脚本：沙袋堆积平衡与约束释放过程模拟
// 适用模块：BlockDyna（块体动力学模块）+ Link 单元 + 刚性面
// 功能说明：模拟沙袋在重力作用下堆积平衡，随后释放 Link 约束观察散体响应
// ============================================================================

// 设置当前工作路径为脚本所在目录
setCurDir(getSrcDir());

// ============================================================================
// 第一阶段：全局参数设置
// ============================================================================

// 打开力学计算开关
dyna.Set("Mechanic_Cal 1");

// 设置系统收敛的不平衡率
dyna.Set("UnBalance_Ratio 1e-5");

// 设置重力加速度（Y 方向向下）
dyna.Set("Gravity 0 -9.8 0");

// 打开大变形计算开关
dyna.Set("Large_Displace 1");

// 设置计算结果输出间隔
dyna.Set("Output_Interval 500");

// 设置监测结果输出时步
dyna.Set("Moniter_Iter 100");

// 打开虚拟质量计算开关（加速静力收敛）
dyna.Set("If_Virtural_Mass 1");

// 设置虚拟时步
dyna.Set("Virtural_Step 0.5");

// 打开接触更新计算开关
dyna.Set("If_Renew_Contact 1");

// 设置子空间更新时步
dyna.Set("Renew_Interval 50");

// 设置接触容差
dyna.Set("Contact_Detect_Tol 1e-3");

// ============================================================================
// 第二阶段：几何模型创建
// ============================================================================

// 创建刚性面（支撑平台）
// 定义刚性面顶点坐标（X-Z 平面，Y=0）
var fCoord = new Array();
fCoord[0] = new Array(-2.0, 0.0, -2.0);
fCoord[1] = new Array(22.0, 0.0, -2.0);
fCoord[2] = new Array(22.0, 0.0, 2.0);
fCoord[3] = new Array(-2.0, 0.0, 2.0);

// 创建刚性面：类型 2(三维面), 组号 1, 4 个顶点
rdface.Create(2, 1, 4, fCoord);

// 创建三维长方体块体堆（沙袋主体）
// 参数：长 20m, 高 15m, 宽 2m, X 方向 40 单元，Y 方向 30 单元，Z 方向 4 单元，组号 2
blkdyn.GenBrick3D(20, 15, 2, 40, 30, 4, 2);

// ============================================================================
// 第三阶段：接触面创建与更新
// ============================================================================

// 将组号为 2 的单元的自由面设定为接触面
blkdyn.CrtBoundIFaceByGroup(2);

// 更新接触面网格
blkdyn.UpdateIFaceMesh();

// ============================================================================
// 第四阶段：材料与本构设置
// ============================================================================

// 设置块体单元模型为 Mohr-Coulomb 理想弹塑性模型
blkdyn.SetModel("MC");

// 设置块体材料参数
// 参数：密度 1900kg/m³, 弹性模量 3e8Pa, 泊松比 0.35, 粘聚力 0, 抗拉强度 0, 
//       内摩擦角 30°, 剪胀角 0°, 组号 2
blkdyn.SetMatByGroup(1900, 3e8, 0.35, 0.0, 0.0, 30.0, 0.0, 2);

// 设置接触面模型为脆性断裂的 Mohr-Coulomb 本构
blkdyn.SetIModel("brittleMC");

// 接触面刚度从单元属性自动获取（比例系数 1.0）
blkdyn.SetIStiffByElem(1.0);

// 接触面强度从单元属性自动获取
blkdyn.SetIStrengthByElem();

// ============================================================================
// 第五阶段：Link 单元创建与设置（模拟沙袋包裹）
// ============================================================================

// 从组号 2 单元的外表面创建 Link 单元，Link 组号为 3
link.CreateFromElemByGroup(2, 3);

// 设置 Link 单元材料参数
// 参数：截面积 0.001m², 弹性模量 1e7Pa, 剪切模量 1e7Pa, 抗拉强度 1e6Pa, 组号 3
link.SetPropByGroup(0.001, 1e7, 1e7, 1e6, 3);

// 设置 Link 单元模型为线弹性模型
link.SetModelByGroup("linear", 3);

// ============================================================================
// 第六阶段：边界条件与阻尼设置
// ============================================================================

// 设置较大的局部阻尼以加速静力平衡收敛（静力问题推荐 0.8）
blkdyn.SetLocalDamp(0.8);

// ============================================================================
// 第七阶段：监测点设置
// ============================================================================

// 监测 4 个测点的 Y 方向位移
dyna.Monitor("block", "ydis", 0, 15, 0);
dyna.Monitor("block", "ydis", 5, 15, 0);
dyna.Monitor("block", "ydis", 10, 15, 0);
dyna.Monitor("block", "ydis", 15, 15, 0);

// ============================================================================
// 第八阶段：第一阶段求解（带 Link 约束，至静力平衡）
// ============================================================================

// 输出阶段信息
print("=== 第一阶段：带 Link 约束求解至静力平衡 ===");

// 求解至系统稳定
dyna.Solve();

// 保存第一阶段结果
dyna.Save("SandBag_Stage1.sav");

// ============================================================================
// 第九阶段：第二阶段求解（删除 Link 约束，观察散体响应）
// ============================================================================

// 输出阶段信息
print("=== 第二阶段：删除 Link 约束，观察散体响应 ===");

// 删除组号为 3 的 Link 单元（模拟沙袋包裹失效）
link.DeleteByGroup(3);

// 第二阶段改为动力时程计算，减小阻尼
blkdyn.SetLocalDamp(0.02);

// 设置动力计算时步
dyna.Set("Time_Step 1e-4");

// 关闭虚拟质量计算（动力计算不需要）
dyna.Set("If_Virtural_Mass 0");

// 执行第二阶段动力时程计算（5000 步）
dyna.DynaCycle(5000);

// 保存第二阶段结果
dyna.Save("SandBag_Stage2.sav");

// ============================================================================
// 第十阶段：输出完成信息
// ============================================================================

print("=== 计算完成 ===");
print("第一阶段结果文件：SandBag_Stage1.sav");
print("第二阶段结果文件：SandBag_Stage2.sav");
print("监测点坐标：(0,15,0), (5,15,0), (10,15,0), (15,15,0)");

// ============================================================================
// CDEM 块体模块仿真脚本：双物体动态碰撞过程模拟
// 适用模块：BlockDyna（块体动力学模块）
// 功能说明：模拟上方物体在重力/初速作用下与下方固定支撑结构的碰撞过程
// 网格文件：cdem.out（Patran 格式二维网格）
// ============================================================================

// 设置当前工作路径为脚本所在目录
setCurDir(getSrcDir());

// ============================================================================
// 一、全局参数设置
// ============================================================================

// 打开力学计算开关
dyna.Set("Mechanic_Cal 1");

// 设置三个方向的重力加速度（Y 方向向下为负）
dyna.Set("Gravity 0 -9.8 0");

// 打开大变形计算开关（碰撞涉及大位移）
dyna.Set("Large_Displace 1");

// 设置计算结果的输出间隔为 500 步
dyna.Set("Output_Interval 500");

// 设置监测信息输出时步为 100 步
dyna.Set("Moniter_Iter 100");

// 关闭虚质量计算开关
dyna.Set("If_Virtural_Mass 0");

// 打开接触更新计算开关（碰撞过程需实时更新接触）
dyna.Set("If_Renew_Contact 1");

// 设置子空间格子更新步长为 100 步
dyna.Set("Renew_Interval 100");

// 设置接触搜索容差为 1mm
dyna.Set("Contact_Detect_Tol 1e-3");

// 设置接触搜索模式为九宫格法（网格尺度较均匀时使用）
dyna.Set("Contact_Search_Method 1");

// 设置空间格子最大尺寸（根据模型尺度调整）
dyna.Set("Max_Cell_Length 0.5");

// 打开 save 文件自动保存开关
dyna.Set("SaveFile_Out 1");

// 设置计算时步（根据模型稳定性确定）
dyna.Set("Time_Step 1e-5");

// ============================================================================
// 二、模型导入与组号划分
// ============================================================================

// 从当前文件夹导入 Patran 格式的网格文件
blkdyn.ImportGrid("patran", "cdem.out");

// 创建坐标范围数组用于划分组号
// 组 2：下方支撑结构（Y 坐标范围 -1e10 到 19.01）
var x = new Array(-1e10, 1e10);
var y = new Array(-1e10, 19.01);
var z = new Array(-1e10, 1e10);

// 将设定范围内的单元组号更改为 2 号（下方支撑结构）
blkdyn.SetGroupByCoord(2, x[0], x[1], y[0], y[1], z[0], z[1]);

