dyna.Set("Gravity 0 -9.8 0");

// 静力平衡阶段关闭大变形
dyna.Set("Large_Displace 0");

// 设置计算结果输出间隔
dyna.Set("Output_Interval 500");

// 关闭虚质量计算（静力阶段）
