//   参数 10: 爆轰载荷持续时间 (s)

// 假设爆源点位于钻孔中心，根据监测点位置推断钻孔大致在 (10, 10, 0) 附近
var blastPos = [10.0, 10.0, 0.0];

// 设置全局 Landau 炸药参数（乳化炸药典型参数）
blkdyn.SetLandauSource(1, 1150, 5000, 3.1e6, 3.0, 1.3333, 7e9, blastPos, 0.0, 10);

// 将爆源绑定到炸药区域（组 2）
// 参数：爆源 ID, 起始组号，结束组号
blkdyn.BindLandauSource(1, 2, 2);

// ============================================================================
// 阻尼设置
// ============================================================================

// 设置局部阻尼系数（爆破问题建议较小值以减少能量耗散）
blkdyn.SetLocalDamp(0.0);

// 设置瑞利阻尼系数
// 参数：刚度阻尼系数，质量阻尼系数
// 刚度阻尼用于滤除高频数值振荡，质量阻尼用于控制低频响应
blkdyn.SetRayleighDamp(1e-6, 0.0);

// ============================================================================
// 监测点设置
// ============================================================================

// 监测点 1: 坐标 (11, 10, 0)，记录 X 方向应力 (sxx) 时程
// 用于分析爆破应力波在岩体中的传播特征
dyna.Monitor("block", "sxx", 11, 10, 0);

// 监测点 2: 坐标 (13, 10, 0)，记录 X 方向应力 (sxx) 时程
// 距离爆源更远，用于分析应力波衰减规律
dyna.Monitor("block", "sxx", 13, 10, 0);

// 监测点 3: 坐标 (16, 10, 0)，记录 X 方向应力 (sxx) 时程
// 最远监测点，用于分析远场应力波特征
dyna.Monitor("block", "sxx", 16, 10, 0);

// ============================================================================
