// ============================================================================
// CDEM 块体模块仿真脚本：基于 Lee-Tarver 模型的炸药冲击起爆动力学模拟
// 适用模块：BlockDyna（块体动力学模块）
// 功能说明：模拟炸药在外界物理扰动下的冲击起爆过程，采用 Lee-Tarver 反应速率模型
//          刻画炸药从受到冲击到发生化学反应并转化为爆轰及围岩响应的过程
// 网格文件：GDEM.msh（Gmsh 格式二维网格）
// 岩体区域：组 1（线弹性模型）
// 爆源区域：组 2（Lee-Tarver 反应速率模型 + JWL 状态方程）
// 接触模型：brittleMC（脆性 Mohr-Coulomb 接触模型）
// ============================================================================

// -------------------------
// 1. 初始化仿真环境
// -------------------------
setCurDir(getSrcDir());
igeo.clear();
imeshing.clear();
dyna.Clear();
doc.clearResult();

// -------------------------
// 2. 全局参数设置
// -------------------------
// 打开力学计算开关
dyna.Set("Mechanic_Cal 1");

// 设置重力加速度为 0（爆破问题通常忽略重力）
dyna.Set("Gravity 0.0 0.0 0.0");

// 打开大变形计算开关（爆破涉及大变形）
dyna.Set("Large_Displace 1");

// 设置计算结果输出间隔（每 100 步输出一次）
dyna.Set("Output_Interval 100");

// 设置监测信息输出时步（每 10 步输出一次监测数据）
dyna.Set("Monitor_Iter 10");

// 关闭虚质量计算开关
dyna.Set("If_Virtural_Mass 0");

// 打开接触更新开关（确保接触面随变形更新）
dyna.Set("If_Renew_Contact 1");

// 设置接触检测容差
dyna.Set("Contact_Detect_Tol 0.001");

// -------------------------
// 3. 导入网格与建立接触面
// -------------------------
// 导入 Gmsh 格式的二维网格文件
blkdyn.ImportGrid("gmsh", "GDEM.msh");

// 创建接触面（组 1 与组 2 之间的界面）
blkdyn.CrtIFace(1);
blkdyn.CrtIFace(-1, -1);
blkdyn.UpdateIFaceMesh();

// -------------------------
// 4. 材料本构模型设置
// -------------------------
// 岩体区域（组 1）采用线弹性模型
blkdyn.SetModel("linear", 1);

// 炸药区域（组 2）采用 Lee-Tarver 反应速率模型
blkdyn.SetModel("LeeTarver", 2);

// -------------------------
// 5. 材料参数定义
// -------------------------
// 岩体线弹性参数
// 参数顺序：密度 (kg/m³)、弹性模量 (Pa)、泊松比、粘聚力 (Pa)、内摩擦角 (°)、抗拉强度 (Pa)、剪胀角 (°)
blkdyn.SetMat(1, 2500, 30e9, 0.25, 10e6, 35, 5e6, 15);

// 炸药 Lee-Tarver 模型参数
// 参数顺序：密度 (kg/m³)、弹性模量 (Pa)、泊松比、粘聚力 (Pa)、内摩擦角 (°)、抗拉强度 (Pa)、剪胀角 (°)、材料标识 (2 表示 Lee-Tarver)
blkdyn.SetMat(2, 1680, 8e9, 0.307, 3e6, 35, 1e6, 15, 2);

// -------------------------
// 6. JWL 状态方程参数设置
// -------------------------
// 设置 JWL 爆源参数
// 参数：序号、装药密度、初始比内能、A、B、R1、R2、Omega、P_CJ、爆速、点火坐标、点火时间、持续时间
// 注意：冲击起爆模式下 (Lee-Tarver)，点火时间和点火坐标不起作用，由冲击波触发
blkdyn.SetJWLSource(1, 1680, 7.0e9, 371.2e9, 3.2e9, 4.2, 0.95, 0.30, 21e9, 7830, [5, 5, 0], 1e-4, 15e-3);

// 将 JWL 源绑定到炸药区域（组 2）
blkdyn.BindJWLSource(1, 2, 2);

// -------------------------
// 7. Lee-Tarver 反应速率参数设置
// -------------------------
// 设置 Lee-Tarver 点火增长模型参数
// 公式：dλ/dt = I(1-λ)^b(ρ/ρ0-1-a)^x + G1(1-λ)^cλ^d p^y + G2(1-λ)^eλ^g p^z
// 参数说明：
//   iNumber=1: 参数序号
//   fI=7.43e11: 点火项系数 (us^-1)
//   fa=0.0005: 临界压缩度参数
//   fb=0.667: 点火项反应度指数
//   fc=0.667: 增长项反应度指数
//   fd=0.111: 增长项反应度指数
//   fe=0.333: 快反应项反应度指数
//   fg=1.0: 快反应项反应度指数
//   fx=20.0: 点火项密度指数
//   fy=1.0: 增长项压力指数
//   fz=2.0: 快反应项压力指数
//   fG1=3.1: 增长项系数 (Mbar^-y us^-1)
//   fG2=400: 快反应项系数 (Mbar^-z us^-1)
//   λ_igmax=0.3: 点火项最大反应度
//   λ_G1max=0.50: 增长项最大反应度
//   λ_G2min=0.0: 快反应项最小反应度
//   iFireMode=1: 点火模式 (1-压力点火，2-时间点火)
blkdyn.SetLeeTarverSource(1, 7.43e11, 0.0005, 0.667, 0.667, 0.111, 0.333, 1.0, 20.0, 1.0, 2.0, 3.1, 400, 0.3, 0.50, 0.0, 1);

// 将 Lee-Tarver 源绑定到炸药区域（组 2）
blkdyn.BindLeeTarverSource(1, 2, 2);

// -------------------------
// 8. 接触面模型设置
// -------------------------
// 设置接触面模型为脆性 Mohr-Coulomb 模型
blkdyn.SetIModel("brittleMC");

// 按单元设置接触面强度参数
blkdyn.SetIStrengthByElem();

// 设置接触面材料参数
// 参数：法向刚度、切向刚度、粘聚力、内摩擦角、抗拉强度、组 1ID、组 2ID
blkdyn.SetIMat(1e14, 1e14, 5e6, 30, 2e6, 1, 2);

// -------------------------
// 9. 边界条件设置
// -------------------------
// 设置静态无反射边界条件以模拟半无限空间
// 左边界 (x ≈ 0)
blkdyn.SetQuietBoundByCoord(-1e-3, 1e-3, -1e5, 1e5, -1e5, 1e5);

// 右边界 (x ≈ 10)
blkdyn.SetQuietBoundByCoord(9.999, 11, -1e5, 1e5, -1e5, 1e5);

// 下边界 (y ≈ 0)
blkdyn.SetQuietBoundByCoord(-1e5, 1e5, -1e-3, 1e-3, -1e5, 1e5);

// -------------------------
// 10. 监测点设置
// -------------------------
// 监测炸药内部特定位置的竖向应力 (syy) 以观察爆轰波的形成
// 监测点 1: 炸药区域内部位置 (5.0, 5.0, 0)
blkdyn.AddMonitor(1, 5.0, 5.0, 0, "syy");

// 监测点 2: 炸药区域内部位置 (5.5, 5.0, 0)
blkdyn.AddMonitor(2, 5.5, 5.0, 0, "syy");

// 监测点 3: 炸药区域内部位置 (6.0, 5.0, 0)
blkdyn.AddMonitor(3, 6.0, 5.0, 0, "syy");

// -------------------------
// 11. 求解控制设置
// -------------------------
// 设置总计算时间 (单位：秒，爆破问题通常为毫秒级)
var totalTime = 50e-6;  // 50 微秒

// 设置自动时步（CDEM 会根据 CFL 条件自动计算稳定时步）
blkdyn.SetAutoTimeStep(1);

// 设置最小允许时步（防止时步过小导致计算过慢）
blkdyn.SetMinTimeStep(1e-10);

// -------------------------
// 12. 执行求解
// -------------------------
// 开始动力学计算
blkdyn.Solve(totalTime);

// -------------------------
// 13. 计算完成提示
// -------------------------
print("=== 冲击起爆模拟计算完成 ===");
print("总计算时间：" + totalTime + " s");
print("请查看结果文件分析爆轰波传播及岩体响应");

