function getDistance(x1, y1, x2, y2) {
    return Math.sqrt(Math.pow(x2 - x1, 2) + Math.pow(y2 - y1, 2));
}

function isCollision(x1, y1, r1, x2, y2, r2) {
    let distance = getDistance(x1, y1, x2, y2);
    return (distance <= r1 + r2);
}

