// ============================================================================

// 打开固体力学计算开关
dyna.Set("Mechanic_Cal 1");

// 设置系统不平衡率收敛准则（静力阶段要求较高精度）
dyna.Set("UnBalance_Ratio 1e-5");

// 设置重力加速度（Y 方向向下为负）
dyna.Set("Gravity 0 -9.8 0");

// 静力平衡阶段关闭大变形
dyna.Set("Large_Displace 0");

// 设置计算结果输出间隔
dyna.Set("Output_Interval 500");

// 关闭虚质量计算（静力阶段）
dyna.Set("If_Virtural_Mass 0");

// 设置接触容差为 1mm
dyna.Set("Contact_Detect_Tol 1e-3");

// 开启接触更新计算
dyna.Set("If_Renew_Contact 1");

// 设置子空间更新时步
dyna.Set("Renew_Interval 100");

// 关闭 save 文件自动保存
dyna.Set("SaveFile_Out 0");

// ============================================================================
// 第二阶段：网格导入与接触面创建
// ============================================================================

// 导入 Ansys 格式网格文件
blkdyn.ImportGrid("ansys", "Landslide.dat");

// 在组 1（基岩）与组 2（滑体）交界面创建接触面
blkdyn.CrtIFace(1, 2);

// 在组 2（滑体）内部创建接触面
blkdyn.CrtIFace(2, 2);

// 对组 1（基岩）自由面创建边界接触面
blkdyn.CrtBoundIFaceByGroup(1);

// 更新接触面网格
blkdyn.UpdateIFaceMesh();

// ============================================================================
// 第三阶段：材料参数设置（静力平衡阶段）
// ============================================================================

// 设置所有单元为线弹性模型
blkdyn.SetModel("linear");

// 设置组 1（基岩）材料参数
// 参数顺序：密度，弹性模量，泊松比，粘聚力，抗拉强度，内摩擦角，剪胀角，组号
blkdyn.SetMatByGroup(2600, 5e9, 0.25, 5e6, 2e6, 35.0, 10.0, 1);

// 设置组 2（滑体）材料参数
blkdyn.SetMatByGroup(2400, 3e9, 0.28, 3e6, 1e6, 30.0, 8.0, 2);

// 设置接触面模型为线弹性（静力平衡阶段）
blkdyn.SetIModel("linear");

// 设置接触面材料参数
// 参数顺序：法向刚度，切向刚度，粘聚力，抗拉强度，内摩擦角
blkdyn.SetIMat(1e9, 1e9, 1e5, 1e4, 25.0);

// ============================================================================
// 第四阶段：边界条件设置
// ============================================================================

// 固定坐标 (0,0,0) 处节点的 X 方向速度
blkdyn.FixVByCoord("x", 0.0, -0.001, 0.001, -0.001, 0.001, -0.001, 0.001);

// 固定坐标 (15,0,0) 处节点的 X 方向速度
blkdyn.FixVByCoord("x", 0.0, 14.999, 15.001, -0.001, 0.001, -0.001, 0.001);

// 模型底部施加 Y 方向约束（防止刚体位移）
blkdyn.FixVByCoord("y", 0.0, -1e10, 1e10, -1e10, 0.001, -1e10, 1e10);

// ============================================================================
// 第五阶段：监测点设置
// ============================================================================

// 监测滑体典型节点的位移和速度
// 监测点 1：滑体中部
dyna.Monitor("block", "xdis", 7.5, 5.0, 0);
dyna.Monitor("block", "ydis", 7.5, 5.0, 0);
dyna.Monitor("block", "xvel", 7.5, 5.0, 0);
dyna.Monitor("block", "yvel", 7.5, 5.0, 0);

// 监测点 2：滑体前缘
dyna.Monitor("block", "xdis", 12.0, 3.0, 0);
dyna.Monitor("block", "ydis", 12.0, 3.0, 0);
dyna.Monitor("block", "xvel", 12.0, 3.0, 0);
dyna.Monitor("block", "yvel", 12.0, 3.0, 0);

// ============================================================================
// 第六阶段：静力平衡求解
// ============================================================================

// 执行静力平衡计算，初始化地应力场
dyna.Solve();

// 保存静力平衡状态
dyna.Save("Landslide_Static.sav");

// ============================================================================
// 第七阶段：切换至动力失稳模拟
// ============================================================================

// 将接触面模型切换为 Mohr-Coulomb 脆性断裂模型（模拟滑动破坏）
blkdyn.SetIModel("brittleMC");

// 更新接触面材料参数（脆性断裂模型）
// 参数顺序：法向刚度，切向刚度，粘聚力，抗拉强度，内摩擦角
blkdyn.SetIMat(1e9, 1e9, 5e4, 5e3, 28.0);

// 开启大变形计算（动力阶段）
dyna.Set("Large_Displace 1");

// 设置局部阻尼（动力阶段能量耗散）
blkdyn.SetLocalDamp(0.15);

// 设置动力输出间隔（更频繁输出以捕捉动态过程）
dyna.Set("Output_Interval 200");

// 设置监测结果输出时步
dyna.Set("Moniter_Iter 50");

// ============================================================================
// 第八阶段：动力显式积分求解
// ============================================================================

// 执行动力时程计算（模拟滑坡失稳滑动过程）
// 计算 50000 时步，可根据实际收敛情况调整
dyna.Solve(50000);

// 保存最终计算结果
dyna.Save("Landslide_Dynamic.sav");

// ============================================================================
// 第九阶段：输出提示信息
// ============================================================================

// 打印求解完成信息
print("Landslide Simulation Completed Successfully!");
print("Static equilibrium stage: Finished");
print("Dynamic instability stage: Finished");
print("Results saved to: Landslide_Static.sav, Landslide_Dynamic.sav");

