// 定义杆单元起点坐标（固定端）
var fArrayCoord1 = [0.0, 0.0, 0.0];

// 定义杆单元终点坐标（加载端）
var fArrayCoord2 = [0.0, 10.0, 0.0];

// 创建桩单元，沿 Y 轴方向，长度 10m，分割为 20 个单元
// 参数说明："pile"为桩单元类型，fArrayCoord1/2 为两端坐标，20 为单元分割数
bar.CreateByCoord("pile", fArrayCoord1, fArrayCoord2, 20);

// ============================================================================
// 3. 杆单元本构模型设置
// ============================================================================

// 指定桩单元为线弹性模型
