bar.SetModelByID("linear", 1, 100);

// ============================================================================
// 4. 杆单元材料参数设置
// ============================================================================

// 设置桩单元材料参数列表（共 11 个参数）
// 参数顺序：[杆件直径，杆件密度，杆件弹性模量，杆件泊松比，
//          杆件抗拉强度，杆件抗压强度，杆件与围岩间浆液的粘聚力，
//          杆件与围岩浆液的内摩擦角，浆锚之间的刚度，
//          杆件的局部阻尼系数，杆件的刚度阻尼系数]
// 单位：m, kg/m³, Pa, Pa, Pa, Pa, Pa, deg, N/m, -, -
var BarProp1 = [
    0.5,        // 杆件直径 (m)
    7800.0,     // 杆件密度 (kg/m³)
    2e10,       // 杆件弹性模量 (Pa)
    0.2,        // 杆件泊松比
    235e6,      // 杆件抗拉强度 (Pa)
    235e6,      // 杆件抗压强度 (Pa)
    1e6,        // 浆液粘聚力 (Pa)
    35.0,       // 浆液内摩擦角 (deg)
    1e9,        // 浆锚刚度 (N/m)
    0.8,        // 局部阻尼系数
    0.0         // 刚度阻尼系数
];

// 施加杆单元材料参数
// 参数说明：BarProp1 为材料参数数组，1-10 为杆件 ID 范围，1-100 为单元 ID 范围
bar.SetPropByID(BarProp1, 1, 10, 1, 100);

// ============================================================================
// 5. 边界条件设置
// ============================================================================

// 定义固定自由度数组（true 表示固定该方向）
// 顺序：[X 方向平动，Y 方向平动，Z 方向平动]
var bArrayType = [true, true, true];

// 定义固定速度值数组（单位：m/s）
var fArrayValue = [0.0, 0.0, 0.0];

// 固定左侧节点（起点端）的平动速度
// 参数说明：bArrayType 为自由度数组，fArrayValue 为速度值，1-10 为杆件 ID 范围，1-1 为节点 ID 范围
bar.FixVelByID(bArrayType, fArrayValue, 1, 10, 1, 1);

// 固定左侧节点（起点端）的转动速度
// 参数说明：bArrayType 为自由度数组，fArrayValue 为角速度值，1-10 为杆件 ID 范围，1-1 为节点 ID 范围
bar.FixRotateVelByID(bArrayType, fArrayValue, 1, 10, 1, 1);

// ============================================================================
// 6. 荷载施加
// ============================================================================

// 定义节点力数组（单位：N）
// 本案例施加竖直向下（-Y 方向）的拉力，大小为 1e6 N（1000 kN）
var fArrayForce = [0.0, -1e6, 0.0];

// 对右侧节点（终点端）施加节点力
// 参数说明：fArrayForce 为力数组，1-10 为杆件 ID 范围，21-21 为节点 ID 范围（20 个单元对应 21 个节点）
bar.ApplyForceByID(fArrayForce, 1, 10, 21, 21);

// ============================================================================
// 7. 监测点设置
// ============================================================================

// 监测杆件加载端（第 21 号节点）Y 方向的位移响应
// 参数说明："bar"为监测对象类型，"a_ydis"为 Y 方向位移变量，20 为杆件 ID，0,0 为附加参数
dyna.Monitor("bar", "a_ydis", 20, 0, 0);

// 监测杆件中点（第 11 号节点）Y 方向的位移响应
dyna.Monitor("bar", "a_ydis", 10, 0, 0);

// 监测杆件固定端（第 1 号节点）Y 方向的位移响应（应接近 0）
dyna.Monitor("bar", "a_ydis", 1, 0, 0);

// ============================================================================
// 8. 执行求解
// ============================================================================

// 求解至稳定状态（自动判断收敛）
dyna.Solve();

