// CDEM 孔隙 - 裂隙双重介质耦合渗流仿真脚本
// 适用模块：BlockDyna（块体模块）+ PoreSP（孔隙渗流）+ FracSP（裂隙渗流）
// 功能说明：模拟孔隙介质与裂隙介质之间的耦合渗流过程
// 网格文件：porefracgrid.msh（GiD 格式二维网格）
// ============================================================================

// 设置当前工作路径为脚本所在目录
setCurDir(getSrcDir());

// 清空已有模型和数据
igeo.clear();
imeshing.clear();
dyna.Clear();
doc.clearResult();

// ============================================================================
// 1. 全局参数设置
// ============================================================================

// 关闭力学计算，仅进行渗流分析
dyna.Set("Mechanic_Cal", 0);

// 开启孔隙渗流模块配置
dyna.Set("Config_PoreSeepage", 1);

// 开启孔隙渗流计算开关
dyna.Set("PoreSeepage_Cal", 1);

// 开启裂隙渗流模块配置
dyna.Set("Config_FracSeepage", 1);

// 开启裂隙渗流计算开关
dyna.Set("FracSeepage_Cal", 1);

// 开启孔隙 - 裂隙耦合交换功能
dyna.Set("PoreFrac_Coupling", 1);

// 设置渗流模式：1-瞬态可压缩液体渗流
dyna.Set("Seepage_Mode", 1);

// 设置计算时步（秒）
dyna.Set("Time_Step", 0.01);

// 设置结果输出间隔（步数）
dyna.Set("Output_Interval", 100);

// 设置监测输出间隔（步数）
dyna.Set("Moniter_Iter", 50);

// 设置总计算步数
var totalSteps = 5000;

// ============================================================================
// 2. 导入网格
// ============================================================================

// 导入 GiD 格式的二维网格文件
blkdyn.ImportGrid("gid", "porefracgrid.msh");

// ============================================================================
// 3. 定义孔隙渗流材料属性
// ============================================================================

// 定义 X、Y、Z 三个方向的渗透系数（单位：m²/(Pa·s)）
var arrayK_pore = new Array(1e-12, 1e-12, 1e-12);

// 设置孔隙渗流参数
// 参数顺序：流体密度 (kg/m³)、体积模量 (Pa)、初始饱和度、孔隙率、渗透系数数组、比奥系数
// 通过坐标范围设置全模型孔隙参数（根据实际网格尺寸调整坐标范围）
poresp.SetPropByCoord(1000.0, 2.2e9, 1.0, 0.15, arrayK_pore, 1.0, 
                      -1e10, 1e10, -1e10, 1e10, -1e10, 1e10);

// ============================================================================
// 4. 创建裂隙单元并设置裂隙渗流参数
// ============================================================================

// 从块体单元创建裂隙网格（假设裂隙已存在于网格中，组号为 2）
// 如果裂隙是独立单元，需要通过相应接口创建
fracsp.CreateGridFromBlock(2);

// 设置裂隙渗流参数
// 参数顺序：裂隙开度 (m)、法向刚度 (Pa/m)、切向渗透率 (m²)、法向渗透率 (m²)
// 此处假设裂隙开度为 0.5mm，渗透率高于孔隙介质
fracsp.SetProp(5e-4, 1e10, 1e-9, 1e-9);

// ============================================================================
// 5. 初始化压力与饱和度场
// ============================================================================

// 初始化全模型初始压力为 0 Pa（大气压参考）
// 初始化饱和度为 1.0（完全饱和）
poresp.InitConditionByCoord(0.0, 1.0, -1e10, 1e10, -1e10, 1e10, -1e10, 1e10);

// 初始化裂隙初始压力场
fracsp.InitConditionByCoord(0.0, 1.0, -1e10, 1e10, -1e10, 1e10, -1e10, 1e10);

// ============================================================================
// 6. 施加边界条件
// ============================================================================

// 定义压力梯度（此处为恒定压力，梯度为 0）
var fArrayGrad = new Array(0.0, 0.0, 0.0);

// 在裂隙边界 X=10~11, Y=0 附近施加恒定水压力 5e4 Pa
// 使用 ApplyConditionByCoord 对坐标范围内的裂隙节点施加压力边界
fracsp.ApplyConditionByCoord("pp", 5e4, fArrayGrad, 
                             10.0, 11.0,    // X 范围
                             -0.1, 0.1,     // Y 范围（包含 y=0）
                             -1e10, 1e10,   // Z 范围（二维问题）
                             false);        // false 表示精确匹配坐标范围

// 可选：在模型其他边界施加排水边界（压力为 0）
// poresp.ApplyConditionByCoord("pp", 0.0, fArrayGrad, 
//                              -1e10, 1e10, -1e10, -0.1, -1e10, 1e10, true);

// ============================================================================
// 7. 执行求解
// ============================================================================

// 调用耦合渗流核心求解器执行仿真计算
dyna.Solve(totalSteps);

// ============================================================================
// 8. 输出完成信息
// ============================================================================

print("孔隙 - 裂隙耦合渗流计算完成！");
print("总计算步数：", totalSteps);
print("结果文件已输出至当前工作目录");

// ============================================================================
// CDEM 块体模块仿真脚本：炸药爆轰载荷下岩石破碎过程模拟
// 适用模块：BlockDyna（块体动力学模块）
// 功能说明：模拟炸药起爆产生的冲击波在岩石中传播及裂纹萌生扩展过程
// 网格文件：circleblast.msh（Gmsh 格式二维网格，半径 0.5m，圆心 (0,0)）
// 网格分组：组 1-岩石区域，组 2-炸药爆源区域
// ============================================================================

// 设置当前工作路径为脚本所在目录
setCurDir(getSrcDir());

// 清除已有模型数据
dyna.Clear();
doc.clearResult();

// ============================================================================
// 全局计算参数设置
// ============================================================================
// 打开力学计算开关
dyna.Set("Mechanic_Cal 1");

// 设置重力加速度为 0（爆破问题重力影响可忽略）
dyna.Set("Gravity 0.0 0.0 0.0");

// 打开大变形计算开关
dyna.Set("Large_Displace 1");

// 设置计算结果输出间隔（每 50 步输出一次）
dyna.Set("Output_Interval 50");

// 设置监测信息输出时步（每 5 步输出一次监测数据）
dyna.Set("Monitor_Iter 5");

// 关闭虚质量计算
dyna.Set("If_Virtural_Mass 0");

// 打开接触面更新开关
dyna.Set("If_Renew_Contact 1");

// 打开瑞利阻尼计算
dyna.Set("If_Cal_Rayleigh 1");

// ============================================================================
// 网格导入与接触面创建
// ============================================================================
// 导入 Gmsh 格式网格文件
blkdyn.ImportGrid("gmsh", "circleblast.msh");

// 创建所有组间的接触面（不同材料组之间自动离散）
blkdyn.CrtIFace(-1, -1);

// 更新接触面网格拓扑信息
blkdyn.UpdateIFaceMesh();

// ============================================================================
// 材料本构模型设置
// ============================================================================
// 设置岩石区域（组 1）为线弹性本构模型
blkdyn.SetModel("linear");

// 设置炸药区域（组 2）为 Landau 爆源模型（JWL 状态方程）
blkdyn.SetModel("Landau", 2);

// 设置岩石材料参数（密度、弹性模量、泊松比、抗拉强度、粘聚力、内摩擦角、剪胀角）
// 密度 2500kg/m³，弹性模量 50GPa，泊松比 0.25，抗拉强度 15MPa，粘聚力 10MPa，内摩擦角 40°，剪胀角 10°
blkdyn.SetMatByGroupRange(2500, 5e10, 0.25, 15e6, 10e6, 40.0, 10.0, 1, 1);

// 设置炸药材料参数（密度、弹性模量、泊松比等，JWL 模型下这些参数影响较小）
blkdyn.SetMatByGroupRange(1000, 1e9, 0.3, 1e6, 1e6, 30.0, 0.0, 2, 2);

// ============================================================================
// 接触面断裂能模型设置
// ============================================================================
// 设置接触面本构模型为脆性断裂模型
blkdyn.SetIModel("brittleMC");

// 设置岩石内部接触面参数（法向刚度、切向刚度、粘聚力、摩擦角、抗拉强度）
blkdyn.SetIMat(5e10, 5e10, 10e6, 40.0, 15e6, 1, 1);

// 设置岩石与炸药界面接触参数（高刚度保证载荷传递）
blkdyn.SetIMat(1e13, 1e13, 0, 0, 0, 1, 2);

// 设置接触面断裂能参数（拉伸断裂能、剪切断裂能）
// 拉伸断裂能 100 J/m²，剪切断裂能 500 J/m²
blkdyn.SetIFracEnergyByCoord(100, 500, -1, 1, -1, 1, -1, 1);

// ============================================================================
// JWL 爆源模型参数设置
// ============================================================================
// 设置炸药起爆点位置（圆心位置）
var firePos = [0.0, 0.0, 0.0];

// 设置全局 JWL 炸药参数
// 参数说明：序号、装药密度、爆轰产物初始比内能、A、B、R1、R2、Omega、CJ 压力、爆速、起爆点、起爆时间、持续时间
// TNT 炸药典型参数：密度 1600kg/m³，爆速 6900m/s，CJ 压力 21GPa
blkdyn.SetLandauSource(1, 1600, 7.0e9, 371.2e9, 3.23e9, 4.15, 0.95, 0.30, 21.0e9, 6900, firePos, 0.0, 50e-6);

// 将 JWL 爆源模型绑定到炸药区域（组 2）
blkdyn.BindLandauSource(1, 2, 2);

// ============================================================================
// 边界条件设置
// ============================================================================
// 设置模型外边界无反射粘性边界条件（模拟无限域，防止应力波反射）
// 二维模型半径 0.5m，在边界附近设置吸收层

// 上边界（Y 正方向）
var selTop = new SelElemFaces(blkdyn);
selTop.box(-0.5, 0.49, -0.01, 0.5, 0.51, 0.01);
blkdyn.applyNonReflectionBySel(selTop);

// 下边界（Y 负方向）
var selBottom = new SelElemFaces(blkdyn);
selBottom.box(-0.5, -0.51, -0.01, 0.5, -0.49, 0.01);
blkdyn.applyNonReflectionBySel(selBottom);

// 左边界（X 负方向）
var selLeft = new SelElemFaces(blkdyn);
selLeft.box(-0.51, -0.5, -0.01, -0.49, 0.5, 0.01);
blkdyn.applyNonReflectionBySel(selLeft);

// 右边界（X 正方向）
var selRight = new SelElemFaces(blkdyn);
selRight.box(0.49, -0.5, -0.01, 0.51, 0.5, 0.01);
blkdyn.applyNonReflectionBySel(selRight);

// 二维计算约束 Z 方向位移
var selAllNodes = new SelNodes(blkdyn);
selAllNodes.box(-10, -10, -10, 10, 10, 10);
blkdyn.SetVel(selAllNodes, "z", 0);

// ============================================================================
// 阻尼设置
// ============================================================================
// 设置局部阻尼系数（爆破问题阻尼不宜过大）
blkdyn.SetLocalDamp(0.05);

// 设置瑞利阻尼（刚度阻尼系数、质量阻尼系数）
blkdyn.SetRayleighDamp(1e-7, 0.0);

// ============================================================================
// 监测点设置
// ============================================================================
// 在 X 轴上设置 4 个应力波监测点，监测 Y 方向应力分量
// 监测点坐标：(0.1, 0, 0), (0.2, 0, 0), (0.3, 0, 0), (0.4, 0, 0)
dyna.Monitor("block", "syy", 0.1, 0.0, 0.0);
dyna.Monitor("block", "syy", 0.2, 0.0, 0.0);
dyna.Monitor("block", "syy", 0.3, 0.0, 0.0);
dyna.Monitor("block", "syy", 0.4, 0.0, 0.0);

// 同时监测 X 方向应力
dyna.Monitor("block", "sxx", 0.1, 0.0, 0.0);
dyna.Monitor("block", "sxx", 0.2, 0.0, 0.0);
dyna.Monitor("block", "sxx", 0.3, 0.0, 0.0);
dyna.Monitor("block", "sxx", 0.4, 0.0, 0.0);

// 监测炸药中心位置压力
dyna.Monitor("block", "pressure", 0.0, 0.0, 0.0);

// ============================================================================
// 求解控制设置
// ============================================================================
// 设置自动时步（爆破问题需要较小时间步保证稳定性）
// 最大时步 1e-7s，最小时步 1e-9s
blkdyn.SetTimeStep(1e-7, 1e-9);

// 设置总计算步数（根据波传播时间估算，约 20000 步）
// 应力波传播到 0.5m 边界约需 100e-6s（岩石波速约 5000m/s）
dyna.Set("Max_Step 20000");

// 设置保存文件开关
dyna.Set("SaveFile_Out 1");

// ============================================================================
// 执行求解计算
// ============================================================================
// 开始动力学计算
dyna.Solve();

// ============================================================================
// 脚本说明
// ============================================================================
// 关键参数说明：
// 1. JWL 炸药参数采用 TNT 典型值，可根据实际炸药类型调整
// 2. 岩石材料参数为花岗岩典型值，可根据实际岩性修改
// 3. 断裂能参数影响裂纹扩展行为，需根据试验数据标定
// 4. 时步设置需保证 CFL 稳定性条件，爆破问题建议 1e-7~1e-8s
// 5. 监测点位置可根据分析需求调整
//
// 待确认项：
// 1. 网格文件 circleblast.msh 需确保包含组 1（岩石）和组 2（炸药）的物理组定义
// 2. 网格尺寸需与模型半径 0.5m 匹配
// 3. 如计算不稳定，可减小时步或调整阻尼参数
// ============================================================================

script_versions.context:
物理问题描述：
本案例模拟三维边坡在重力作用下的弹塑性稳定性。场景为一个三维几何坡体，通过逐步施加重力并考虑材料的塑性屈服（Mohr-Coulomb准则），分析坡体的变形趋势及潜在滑动区域。

总体任务目标与要求：
进行三维边坡的塑性稳定性分析。要求生成标准的CDEM JavaScript脚本。包含模型本构切换、平衡求解设置。

几何与网格：
导入GiD格式的“Slope3D.msh”三维网格。

材料与模型：
计算分为两步。初始采用线弹性模型，之后为Mohr-Coulomb理想弹塑性模型。需定义关键参数。

边界条件与监测信息：
使用以下命令对坡体底部及侧向边界分别施加对应的法向约束：
//X方向左侧法向约束
blkdyn.FixVByCoord("x", 0.0, -1e10, -9.99, -1e10, 1e10, -1e10, 1e10);

//X方向右侧法向约束
blkdyn.FixVByCoord("x", 0.0, 29.99, 31, -1e10, 1e10, -1e10, 1e10);

//Y方向底部法向约束
blkdyn.FixVByCoord("y", 0.0, -1e10, 1e10, -1e10, 0.001, -1e10, 1e10);

//Z方向后侧法向约束
blkdyn.FixVByCoord("z", 0.0, -1e10, 1e10, -1e10, 1e10, -1e10, 0.001);

//Z方向前侧法向约束
blkdyn.FixVByCoord("z", 0.0, -1e10, 1e10, -1e10, 1e10, 9.99, 10.01);
监测在(0,10,0),(12,15,0),(15,20,0)的x方向位移响应。

求解控制：
开启虚质量计算辅助收敛。先进行弹性求解并保存结果，再进行塑性迭代。设定系统收敛的不平衡率阈值。

