// ============================================================================
// 第一阶段：全局参数设置（静力平衡阶段）
// ============================================================================

// 打开力学计算开关
dyna.Set("Mechanic_Cal 1");

// 设置重力加速度（Y 方向向下）
dyna.Set("Gravity 0 -9.8 0");

// 打开大位移开关（考虑大变形）
dyna.Set("Large_Displace 1");

// 打开接触更新开关（块体运动过程中更新接触关系）
dyna.Set("If_Renew_Contact 1");

// 设置子空间格子更新步长
dyna.Set("Renew_Interval 100");

// 设置接触容差
dyna.Set("Contact_Detect_Tol 1e-3");

// 设置云图输出间隔
dyna.Set("Output_Interval 500");

// 关闭虚质量计算开关（静力平衡阶段）
dyna.Set("If_Virtural_Mass 0");

// 设置系统不平衡率收敛准则
dyna.Set("UnBalance_Ratio 1e-5");

// ============================================================================
// 第二阶段：网格导入与接触面创建
// ============================================================================

// 导入 Ansys 格式的三维网格文件
blkdyn.ImportGrid("ansys", "groupcheck.dat");

// 对所有块体交界面进行接触面切割（-1,-1 表示所有组号之间）
blkdyn.CrtIFace(-1, -1);

// 更新接触面网格
blkdyn.UpdateIFaceMesh();

// ============================================================================
// 第三阶段：材料与本构设置（静力平衡阶段）
// ============================================================================

// 设置块体单元本构模型为线弹性
blkdyn.SetModel("linear");

// 设置块体材料参数：密度、弹性模量、泊松比、粘聚力、抗拉强度、内摩擦角、剪胀角
// 以下参数为示例假设，用户需根据实际材料调整
blkdyn.SetMat(2500, 1e9, 0.25, 1e7, 5e6, 35.0, 10.0);

// 设置接触面本构模型为线弹性（用于静力平衡阶段）
blkdyn.SetIModel("linear");

// 设置接触面材料参数：法向刚度、切向刚度、内摩擦角、粘聚力、抗拉强度
// 静力阶段接触面刚度设置较大以保证平衡
blkdyn.SetIMat(1e10, 1e10, 15, 1e4, 1e4);

// ============================================================================
// 第四阶段：边界条件设置
// ============================================================================

// 固定 Y 坐标从负无穷到 0 处边界的 Y 方向速度为 0
// 参数说明："y"方向固定，速度值 0，按"y"坐标范围，从 -1e10 到 0.001
blkdyn.FixV("y", 0, "y", -1e10, 0.001);

// 设置静力平衡阶段的局部阻尼系数（静力问题一般取 0.8）
blkdyn.SetLocalDamp(0.8);

// ============================================================================
// 第五阶段：静力平衡求解
// ============================================================================

// 执行静力计算直至达到初始应力平衡（不带参数表示求解至收敛）
dyna.Solve();

print("静力平衡阶段完成！");

// ============================================================================
// 第六阶段：切换至动力失稳阶段
// ============================================================================

// 关闭虚质量开关（确保动力计算准确）
dyna.Set("If_Virtural_Mass 0");

// 将接触面模型切换为脆性断裂 Mohr-Coulomb 模型（模拟接触失效）
blkdyn.SetIModel("brittleMC");

// 设置接触面材料参数：法向刚度、切向刚度、内摩擦角、粘聚力、抗拉强度
// 动力阶段接触面参数可根据实际调整，此处粘聚力和抗拉强度设为 0 模拟完全失效
blkdyn.SetIMat(1e10, 1e10, 35.0, 0.0, 0.0);

// 设置动力计算阶段的局部阻尼系数（动力计算一般取 0.01-0.03）
blkdyn.SetLocalDamp(0.01);

// 自动计算稳定时步（安全系数 0.8）
dyna.TimeStepCorrect(0.8);

// ============================================================================
// 第七阶段：动力失稳求解与结果输出
// ============================================================================

// 运行动力失稳仿真（求解 15000 步，可根据需要调整）
dyna.Solve(15000);

// 输出模型结果文件
dyna.Set("Tecplot_Out 1");
dyna.OutputModelResult();

print("动力失稳仿真完成！");
print("Solution is OK!");

