function generateCirclePoreSeepageParameters(radius, permeability) {
    // 定义X、Y、Z三个方向的渗透系数
    var arrayK = new Array(permeability, permeability, permeability);

    // 指定坐标控制范围内的孔隙渗流参数，依次为流体密度、体积模量、饱和度、孔隙率、渗透系数、比奥系数
    var poreSeepageParameters = {
        fluidDensity: 1000.0,
        bulkModulus: 1e7,
        saturation: 0.0,
        porosity: 0.01,
        permeability: arrayK,
        BiotCoefficient: 1.0,
        timeStep: 1e-6
    };

    return poreSeepageParameters;
}

// 生成圆形孔隙渗流条件
function generateCirclePoreSeepageCondition(radius, pressure) {
    // 定义X、Y、Z三个方向的坐标控制范围
    var coordRange = [-radius, radius, -radius, radius, -radius, radius];

    // 设定模型四周的水压力边界条件
    var poreSeepageCondition = {
        pp: pressure,
        grad: [0.0, 0.0, 0.0],
        coordRange: coordRange
    };

    return poreSeepageCondition;
}

// 生成圆形孔隙渗流参数和条件
function generateCirclePoreSeepage(radius, permeability, pressure) {
    var poreSeepageParameters = generateCirclePoreSeepageParameters(radius, permeability);
    var poreSeepageCondition = generateCirclePoreSeepageCondition(radius, pressure);

    return { parameters: poreSeepageParameters, condition: poreSeepageCondition };
}

// 生成圆形孔隙渗流
function generateCirclePoreSeepage(radius, permeability, pressure) {
    var poreSeepage = generateCirclePoreSeepage(radius, permeability, pressure);

    return poreSeepage;
}

