dyna.Set("If_Renew_Contact 1");

// 设置子空间更新时步为100步
dyna.Set("Renew_Interval 10");

// 设置接触容差为1mm
dyna.Set("Contact_Detect_Tol 2e-3");

// 从当前文件夹下导入patran格式的网格文件
blkdyn.ImportGrid("gid", "tri.msh");

