blkdyn.CrtIFace();

// 更新接触面网格
blkdyn.UpdateIFaceMesh();

// 设定所有单元的本构为线弹性本构
blkdyn.SetModel("linear");

// 设定组号为1-100之间的材料参数
blkdyn.SetMat(2500, 3e8, 0.25, 3e6, 1e6, 40.0, 10.0);

