blkdyn.SetIMat(5e10, 5e10, 10.0, 0.0, 0.0);

// 设定全部节点的局部阻尼系数为0.01
blkdyn.SetLocalDamp(0.005);

// 设置计算时步
dyna.Set("Time_Step 2e-5");

// 计算5万步
dyna.Solve();

